INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-57f41407-moex-00016', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「康德說：『自律使我們與眾不同，自律令我們活得更高級。也正是自律， 使我們獲得更自由的人生。』要想通往自由的遠方，自律應該是你生活中 不可或缺的一項。」 根據上文，下列選項最符合文意的是：', '["凡是擁有自由的人，都不必然懂得自律", "凡是與眾不同的人，都能夠做得到自律", "凡是懂得自律的人，能獲得更自由的人生", "凡是想活得更高級的人，自律是唯一路徑"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00017', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「儘管口述歷史有若干缺點，卻比書寫人物歷史的其他文類更受到重視。一 方面，由於部分檔案文獻被刻意遮掩，口述歷史正好作為補充；另一方面， 傳記和口述歷史都常環繞著重要人物，但無名小卒往往因後者而有被採訪的 機會。再者，受訪者的記憶固然會模糊、錯誤，但畢竟還健在，訪問者除了 查找史料去求證，也可以從他們保存的資料，幫助他們重建過去。」 根據上文，下列有關口述歷史的敘述，何者最適當？', '["真實性往往勝過檔案文獻", "允許採用非當事人的資料", "專門採訪名不見經傳人物", "最終須以在世者記憶為準"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00018', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「多年來，本土價值的提倡已是成為一種習性，卻沒有盡責地闡明本土的 意義。回歸到本土，並不是要摒棄所有的古典與傳統，而應該是追求更開 放的精神，更寬容的境界。所有的古典文學，經過閱讀、解釋、再創造， 就會變成本土價值的一部分。以從容開放的態度看待語文教育中的古典文 學，讓古典回到文化的領域，讓傳統成為人文的價值，本土將因此而多元， 而健康，而茁壯。經過閱讀與再閱讀，創造與再創造，古典是永遠的現代， 古典也是永遠的本土。」 根據上文，下列選項何者最符合文意？', '["提倡鄉土教育", "強調復古思想", "注重經典閱讀的培養", "古典仍具有現代意義"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00019', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「李奧．貝納曾說：『好廣告不僅是流通訊息，而是以欲望和信仰滲透公 眾的心靈。』透過機械複製的輔助（廣告牌、橫幅廣告、電視廣告、廣播 廣告、置入廣告），廣告即可緩慢但穩當地與觀者搭建關係。品牌的首要 目標，就只是成為人們既有世界中更常見的一部分，喜不喜歡它是後來的 事，真正的任務是讓產品成為消費者日常生活的一部分。」 下列選項最符合本文旨意的是：', '["好廣告必須透過機械輔助才能進入消費者的日常生活", "涉及慾望或信仰層面的廣告比較容易滲透消費者心靈", "品牌往往需透過廣告才能在消費者心中建立起好感度", "好廣告會緩慢地讓品牌在消費者腦中留下印象及連結"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00020', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「日本茶藝精神中制式化的練習，具有沉思鍛鍊的價值，無意識地重複機 械性的技巧，使人只專注於存在本身，而不會因需要做決定、從事藝術創 作等而分心。」 根據上文，下列選項何者錯誤？', '["制式化的練習方式可以訓練人們的專注力", "從日本茶藝精神可以推知專注有助於學習", "制式化與機械性的訓練，讓人的視野變得狹隘，是弊大於利", "重複機械性的動作，能助人不受外在事物的影響而導致分心"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00021', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「作為一個科學工作者，其中最重要的是熱愛科學，善於思考，勤於觀察 和蒐集資料、具有相當的發現能力和廣博的常識。這告訴我們，科學並不 是什麼高不可攀的東西。對我們大多數具有『平常能力』的人來說，只要 真正熱愛科學，並能勇於實踐，勤於觀察稍縱即逝的細節和思考現象背後 的玄機，是很有希望在科學上做出不平凡貢獻的。」 根據上文，下列選項何者最符合文意？', '["高度興趣加上勤勞實踐，是從事科學研究的要件", "鼓勵大眾不要畏懼科學，科學其實是簡單的科目", "打破隔行如隔山的迷思，有意識地培養第二專長", "若資質平庸，就無法憑藉觀察激盪出不凡的成果"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00022', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「一九五〇年代，爆發在巴拿馬的香蕉黃葉病，幾乎摧毀了美洲最主要的 香蕉出口產業。這次的災難，造成大米歇爾蕉瀕臨絕種。尖孢鐮孢菌感染 香蕉作物的效率高得令人難以置信，這種真菌經由土壤和水傳播，可以潛 伏在土壤中長達三十年，一旦遇到適當的宿主，它就會循著根部，經由木 質部導管，藉由水分的傳輸感染全部植株，最終香蕉樹會因為脫水而死。」 根據上文，下列選項何者最符合文意？', '["一九五〇年代，巴拿馬出現香蕉黃葉病，重挫了亞非香蕉之出口", "香蕉黃葉病曾經造成蕉農損失慘重，後來才全面改種大米歇爾蕉", "尖孢鐮孢菌經由木質部導管來感染植株，宿主最終將會脫水而死", "尖孢鐮孢菌能潛伏於土壤中長達三十年，主要透過生物授粉傳播"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00023', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「1990年初，《文訊》探訪埔里的知識分子、常民百姓，如何組織自己的 力量，利用土地的自然資源，去改造家鄉的體質，發現了一個樸素的成功 典範。同年四月《文訊》製作了『埔里：藝術的小鎮』專題，就在那時認 識了鄧相揚；專題首篇就是他的〈埔里開發簡史〉。這個專題也引發了《文 訊》1990年底啟動的『各縣市藝文環境調查報告』，對《文訊》的發展方 向產生了影響。」 根據上文，下列選項何者最符合文意？', '["鄧相揚受到《文訊》雜誌啟發而成功改造了家鄉埔里", "〈埔里開發簡史〉一文刊載於1990年初《文訊》雜誌", "鄧相揚曾策劃並參與了「各縣市藝文環境調查報告」", "「埔里：藝術的小鎮」專題影響了《文訊》未來走向"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00024', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「評估一個人有沒有辦法實踐終身學習，關鍵在於他是否具備自我突破的 能耐。以往臺灣的學校教育，最重要的功能莫過於灌輸知識。在經濟起飛 的年代，身為全球產業鏈一環的島嶼，這是養成代工人才最有效率的對策。 但時過境遷，學校培育人才的方法便得從效率導向的直接灌輸，進化成興 趣導向的循循善誘，引導孩子投入『發現自己的無知——尋找答案』的循 環，意即自我突破，這就是終身學習必備的素養。」 根據上文，下列選項最符合文意的是：', '["在經濟起飛的年代，訓練思辨是養成代工人才的好方法", "終身學習的素養教育以兼顧效率導向和興趣導向為目標", "發覺自己無知，進而尋找答案，便能有效率地灌輸知識", "在這個時代，具備自我突破能力的人，才能夠終身學習"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00025', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「這所濱海中學的入口廣場，以挑高的造型屋頂棚架，提供遮風擋雨、隔 熱採光的場所，如同變魔術一般，大幅增加學生四季均可使用的活動空間。 建築物之間，以稍帶弧度的迴廊有秩序地連成一氣，一來建築物間的距離 可拉開，海風自由穿梭於棟舍間，各棟的噪音不致互相影響。二來多出了 半戶外活動空間，學生穿梭於各棟時不致吹風淋雨。」 根據上文，下列選項何者最符合文中學校建築的設計考量？', '["入口廣場棚架採挑高設計，旨在阻隔噪音", "筆直走廊拉開了建物棟距，可使海風流通", "屋頂棚架和棟舍間廊道舒展了學生活動空間", "廊道比棚架更加能豐富校園建築量體的變化"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
